import React from "react";

const ContenedorImagenes = ({ alto, imagenes }) => {
  return (
    <div
      className="w-full flex items-center justify-between px-8 gap-4"
      style={{ height: alto }}
    >
      {imagenes.map((item, index) => (
        <div
          key={index}
          className="relative flex-1 h-full overflow-hidden flex flex-col items-center"
        >
          {/* Imagen */}
          <img
            src={item.ruta}
            alt={item.titulo}
            className="w-full h-4/5 object-cover rounded-lg"
          />

          {/* Título centrado d*/}
          <div className="w-full text-center font-bold text-lg bg-white bg-opacity-70 py-1">
            {item.titulo}
          </div>

          {/* Botón Dashboard */}
          <button
            className="mt-2 bg-green-700 text-white px-4 py-2 rounded hover:bg-green-900 transition"
            onClick={item.onClick}
          >
            Ver Dashboard
          </button>
        </div>
      ))}
    </div>
  );
};

export default ContenedorImagenes;
